1	// Modern Design System Implementation
2	// Clean • Technical • Sophisticated • Minimal • Professional
3	@use "variables" as *;
4	
5	// CSS Custom Properties Setup
6	:root {
7	  // Colors - Earthy Sophisticated with Friendly Touch
8	  --color-primary: #{$earth-coral};
9	  --color-text: #{$earth-text-primary};
10	  --color-text-secondary: #{$earth-text-secondary};
11	  --color-text-muted: #{$earth-text-tertiary};
12	  --color-background: #{$earth-background};
13	  --color-background-subtle: #{$earth-background-subtle};
14	  --color-surface: #{$earth-surface};
15	  --color-accent: #{$accent-primary};
16	
17	  // Typography
18	  --font-primary: #{$font-primary};
19	  --font-secondary: #{$font-secondary};
20	  --font-mono: #{$font-mono};
21	
22	  // Spacing
23	  --space-xs: #{$space-xs};
24	  --space-sm: #{$space-sm};
25	  --space-md: #{$space-md};
26	  --space-lg: #{$space-lg};
27	  --space-xl: #{$space-xl};
28	  --space-2xl: #{$space-2xl};
29	  --space-3xl: #{$space-3xl};
30	  --space-4xl: #{$space-4xl};
31	  --space-5xl: #{$space-5xl};
32	
33	  // Shadows
34	  --shadow-sm: 0 0.4rem 2rem rgba(28, 28, 28, 0.04);
35	  --shadow-md: 0 0.8rem 3rem rgba(28, 28, 28, 0.08);
36	  --shadow-lg: 0 1.6rem 4rem rgba(28, 28, 28, 0.12);
37	
38	  // Border Radius
39	  --radius-sm: 0.4rem;
40	  --radius-md: 0.8rem;
41	  --radius-lg: 1.6rem;
42	  --radius-full: 50%;
43	
44	  // Transitions - Standardized boring.industries timing
45	  --transition-fast: 0.15s cubic-bezier(0.25, 0.46, 0.45, 0.94);
46	  --transition-base: 0.3s cubic-bezier(0.25, 0.46, 0.45, 0.94);
47	  --transition-slow: 0.6s cubic-bezier(0.25, 0.46, 0.45, 0.94);
48	  
49	  // Animation timing for consistency
50	  --easing-standard: cubic-bezier(0.25, 0.46, 0.45, 0.94);
51	  --easing-dramatic: cubic-bezier(0.16, 1, 0.3, 1);
52	  --easing-gentle: ease-out;
53	}
54	
55	// Sophisticated Typography System
56	.hero-title {
57	  font-size: clamp(5.4rem, 12vw, 16rem); // Increased size for impact
58	  font-weight: $font-weight-medium; // Consistent with h1 hierarchy (450)
59	  line-height: 0.88; // Tighter for drama
60	  letter-spacing: -0.06em; // More aggressive kerning
