.text-refined {
  letter-spacing: -0.02em; // Tighter for sophisticated feel
  font-feature-settings: "kern" 1, "liga" 1, "calt" 1;
  text-rendering: optimizeLegibility;
}

.text-editorial {
  font-family: $font-display;
  font-style: italic;
  font-weight: $font-weight-regular;
  letter-spacing: 0.005em;
  line-height: 1.4;
  font-feature-settings: "kern" 1, "liga" 1, "swsh" 1;
}

.text-elegant {
  font-family: $font-display;
  font-style: italic;
  font-weight: $font-weight-light; // Lighter for fine art
  letter-spacing: 0.01em;
  line-height: 1.5;
}

.text-sophisticated {
  font-weight: $font-weight-light;
  letter-spacing: 0.08em; // More spacing for gallery feel
  text-transform: uppercase;
  font-size: 0.8em;
}

.text-luxury {
  font-family: $font-display;
  font-weight: $font-weight-light;
  font-size: 1.15em; // Slightly larger for presence
  line-height: 1.65;
