  line-height: 1.8;
  font-style: normal;
}

.text-fine-art {
  font-family: $font-display;
  font-weight: $font-weight-light;
  font-size: 1.2em;
  letter-spacing: -0.01em;
  line-height: 1.3;
  font-feature-settings: "kern" 1, "liga" 1, "swsh" 1;
}

// Modern Navigation - Clean and minimal with mobile support
.navigation {
  height: 6rem;
  background: #ffffff;
  border-bottom: 1px solid rgba(230, 228, 223, 0.3);
  position: fixed;
  top: 0;
  left: 0;
  right: 0;
  z-index: 1001;
  transition: all var(--transition-fast);

  // Fade-in animation on page load
  opacity: 0;
  transform: translateY(-10px);
  animation: navFadeIn 0.8s ease-out 0.2s forwards;

  &--open {
    background: #ffffff;
  }

  .container {
    max-width: 100%;
    margin: 0;
    padding: 0 $space-2xl;
    height: 100%;
    display: flex;
    align-items: center;
    justify-content: space-between;
    position: relative;

    @media (max-width: $breakpoint-md) {
      padding: 0 $space-lg;
    }

    @media (max-width: $breakpoint-sm) {
      padding: 0 $space-md;
    }
  }

  .nav-brand {
    font-size: 1.8rem;
    font-weight: 500;
    color: $text-primary;
    letter-spacing: -0.01em;
    text-decoration: none;
    transition: all var(--transition-base);
    z-index: 1001;

    &:hover {
      color: $text-secondary;
      text-decoration: none;
    }
  }

  // Mobile hamburger toggle
  .nav-toggle {
    display: none;
    flex-direction: column;
    justify-content: center;
    align-items: center;
    background: transparent;
    border: none;
    cursor: pointer;
    padding: 1rem;
    z-index: 1001;
    min-width: 44px;
    min-height: 44px;
    border-radius: 6px;
    transition: all var(--transition-fast);
    position: relative;

    @media (max-width: $breakpoint-md) {
      display: flex !important;
    }

    &:hover {
      background: rgba(184, 118, 94, 0.05);
    }

    &:active {
      background: rgba(184, 118, 94, 0.1);
    }

    &:focus {
      outline: 2px solid $earth-coral;
      outline-offset: 2px;
    }

    .nav-toggle-line {
      width: 2rem;
      height: 2px;
      background: $text-primary;
      transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);
      margin: 0.25rem 0;
      border-radius: 1px;
      transform-origin: center;
      display: block;
      will-change: transform, opacity;
    }

    &--open {
      .nav-toggle-line:nth-child(1) {
        transform: rotate(45deg) translate(0.65rem, 0.65rem);
      }

      .nav-toggle-line:nth-child(2) {
        opacity: 0;
        transform: scale(0);
      }

      .nav-toggle-line:nth-child(3) {
        transform: rotate(-45deg) translate(0.65rem, -0.65rem);
      }
    }
  }

  .nav-links {
    display: flex;
    gap: $space-xl;
    list-style: none;
    margin: 0;
    padding: 0;

    @media (min-width: calc($breakpoint-md + 1px)) {
      display: flex !important;
      position: static !important;
      transform: none !important;
      opacity: 1 !important;
      visibility: visible !important;
      background: transparent !important;
      backdrop-filter: none !important;
      box-shadow: none !important;
    }

    @media (max-width: $breakpoint-md) {
      position: absolute;
      top: 100%;
      left: 0;
      right: 0;
      background: #ffffff;
      border-top: 1px solid rgba(230, 228, 223, 0.3);
      box-shadow: 0 4px 20px rgba(28, 28, 28, 0.1);
      flex-direction: column;
      align-items: stretch;
      padding: $space-lg 0;
      gap: 0;
      opacity: 0;
      visibility: hidden;
      pointer-events: none;
      transition: opacity 0.3s cubic-bezier(0.4, 0, 0.2, 1), 
                  visibility 0.3s cubic-bezier(0.4, 0, 0.2, 1),
                  transform 0.3s cubic-bezier(0.4, 0, 0.2, 1);
      z-index: 999;
      transform: translateY(-10px);
      will-change: transform, opacity;
    }

    &--open {
      @media (max-width: $breakpoint-md) {
        opacity: 1 !important;
        visibility: visible !important;
        pointer-events: all !important;
        transform: translateY(0) !important;
      }
    }

    a {
      font-size: 1.5rem;
      font-weight: 450;
      color: $text-secondary;
      text-decoration: none;
      position: relative;
      padding: $space-sm $space-md;
      transition: all var(--transition-fast);
      border-radius: 6px;

      @media (max-width: $breakpoint-md) {
        padding: $space-md $space-xl;
        font-size: 1.6rem;
        font-weight: 400;
        color: $text-primary;
        border-bottom: 1px solid rgba(230, 228, 223, 0.2);
        transition: all var(--transition-fast);
        display: block;
        width: 100%;
        text-align: left;

        &:last-child {
          border-bottom: none;
        }

