      padding: 0; // Remove any padding that might offset centering
    }

    .greeting {
      font-size: $font-size-small;
      color: $text-quaternary;
      text-transform: uppercase;
      letter-spacing: 0.12em;
      margin-bottom: $space-xl;
      font-weight: $font-weight-light;

      @media (max-width: $breakpoint-md) {
        text-align: center; // Center on mobile
      }
    }

    h1 {
      margin-bottom: $space-lg;
      line-height: 1.05;
      font-weight: $font-weight-medium;
      max-width: 90%;
      letter-spacing: -0.06em; // Even tighter for more dramatic scale contrast
      font-feature-settings: "kern" 1, "liga" 1;
      text-rendering: optimizeLegibility;
      font-family: $font-primary;

      // Subtle slide-in animation
      opacity: 0;
      transform: translateX(-20px);
      animation: slideInLeft 0.8s ease-out 0.1s forwards;

      @media (max-width: $breakpoint-md) {
        max-width: 100%;
        letter-spacing: -0.03em;
        line-height: 1.1;
        text-align: center; // Center h1 on mobile
      }

      @media (max-width: $breakpoint-sm) {
        font-size: $font-size-h1;
        letter-spacing: -0.02em;
        line-height: 1.15;
        margin-bottom: $space-md;
        text-align: center; // Center h1 on small mobile
      }

      // Animate the wave emoji separately
      .wave-emoji {
        display: inline-block;
        animation: wave 2s ease-in-out infinite, fadeIn 0.8s ease-out 0.8s both;
        transform-origin: 70% 70%;
      }
    }

    .intro {
      font-size: 1.8rem; // Increased from 1.6rem for better presence
      line-height: 1.35; // Tighter for editorial feel
      color: $text-secondary;
      margin-bottom: $space-2xl;
      max-width: 85%;
      font-weight: $font-weight-regular;
      font-family: $font-primary;
      font-style: normal;
      letter-spacing: -0.015em; // Refined letter spacing
      font-feature-settings: "kern" 1, "liga" 1;

      // Subtle fade-in animation
      opacity: 0;
      transform: translateY(10px);
      animation: fadeInUp 0.8s ease-out 0.3s forwards;

      @media (max-width: $breakpoint-md) {
        max-width: 100%; // Full width on mobile
        text-align: center; // Center intro text on mobile
      }

      // Bold keywords styling
      strong, b {
        font-weight: $font-weight-semibold;
        color: $text-primary;
        letter-spacing: -0.015em; // Tighter tracking for bold text
      }

      // Highlight key phrases
      .highlight {
        font-weight: $font-weight-medium;
        color: $earth-coral;
        position: relative;

        &::after {
          content: '';
          position: absolute;
          bottom: -2px;
          left: 0;
          width: 0;
          height: 1px;
          background: $earth-coral;
          transition: width 0.6s ease;
        }

        &:hover::after {
          width: 100%;
        }
      }
    }
  }

