// About page text refinement styling
.text-refined {
  max-width: 65ch;
  margin: 0 auto;
  padding: 0 $space-md;

  @media (max-width: $breakpoint-sm) {
    padding: 0 $space-sm;
  }

  .markdown-content {
    font-size: clamp(1.6rem, 2.2vw, 1.9rem);
    line-height: 1.6;
    letter-spacing: -0.015em;

    p {
      margin-bottom: 2.5rem;

      &:last-child {
        margin-bottom: 0;
      }
    }

    // Enhanced typography effects
    strong, b {
      font-weight: $font-weight-semibold;
      color: $text-primary;
      letter-spacing: -0.02em;
    }

    em, i {
      font-style: italic;
      color: $text-secondary;
      font-weight: $font-weight-medium;
    }
  }
}

// Blog Post Layout - Responsive and Mobile-Optimized
.post-article {
  width: 100%;
  max-width: 100%;
  overflow-x: hidden;

  .post-container {
    padding-top: 2rem; // Design system spacing (32px)

    @media (max-width: $breakpoint-sm) {
      padding-top: 1.5rem; // Design system mobile spacing (24px)
    }
  }

  .post-content {
    max-width: 75ch;
    margin: 0 auto;
    padding: 0 $space-lg;
    word-wrap: break-word;
    overflow-wrap: break-word;

    @media (max-width: $breakpoint-sm) {
      padding: 0 $space-md;
      max-width: 100%;
    }

    .post-header {
      text-align: center;
      margin-bottom: $space-xl;

      h1 {
        font-size: clamp(2.4rem, 5vw, 4.8rem);
        font-weight: $font-weight-medium;
        line-height: 1.1;
        letter-spacing: -0.03em;
        color: $text-primary;
        margin-bottom: $space-md;
        word-wrap: break-word;
        hyphens: auto;
      }

      time {
        font-size: $font-size-small;
        color: $text-secondary;
        font-weight: $font-weight-medium;
      }
    }

    .post-body {
      line-height: 1.7;
      font-size: clamp(1.6rem, 2vw, 1.8rem);
      color: $text-primary;

      // Ensure all content elements are responsive
      * {
        max-width: 100%;
        word-wrap: break-word;
        overflow-wrap: break-word;
      }

      // Typography improvements
      h2, h3, h4, h5, h6 {
        font-weight: $font-weight-medium;
        color: $text-primary;
        margin: $space-xl 0 $space-lg 0;
        line-height: 1.3;
        letter-spacing: -0.02em;
      }

      h2 {
        font-size: clamp(2rem, 4vw, 3.2rem);
      }

      h3 {
        font-size: clamp(1.8rem, 3.5vw, 2.4rem);
      }

      p {
        margin-bottom: $space-lg;

        &:last-child {
          margin-bottom: 0;
        }
      }

      // Code blocks and preformatted text
      pre, code {
        word-wrap: break-word;
        overflow-wrap: break-word;
        white-space: pre-wrap;

        @media (max-width: $breakpoint-sm) {
          font-size: 1.4rem;
        }
      }

      pre {
        overflow-x: auto;
        padding: $space-md;
        background: rgba(0, 0, 0, 0.05);
        border-radius: 8px;
        margin: $space-lg 0;
      }

      // Images
      img {
        max-width: 100%;
        height: auto;
        border-radius: 8px;
        margin: $space-lg 0;
      }

      // Lists
      ul, ol {
        margin-bottom: $space-lg;
        padding-left: $space-lg;
      }

      // Links
      a {
        color: $earth-coral;
        text-decoration: underline;
        text-decoration-thickness: 1px;
        text-underline-offset: 2px;

        &:hover {
          text-decoration-thickness: 2px;
        }
      }

      // Blockquotes
      blockquote {
        border-left: 4px solid $earth-coral;
        padding: $space-md 0 $space-md $space-lg;
        margin: $space-lg 0;
        font-style: italic;
        color: $text-secondary;
      }
    }

    .post-navigation {
      margin-top: $space-3xl;
      padding-top: $space-xl;
      border-top: 1px solid $border-light;

      ul {
        list-style: none;
        padding: 0;
        display: flex;
        justify-content: space-between;
        gap: $space-md;

        @media (max-width: $breakpoint-sm) {
          flex-direction: column;

